import React, { useState, useEffect } from 'react';

const Home = () => {
  const [equipos, setEquipos] = useState([]);

  useEffect(() => {
    fetch("https://site.api.espn.com/apis/site/v2/sports/basketball/nba/teams")
      .then(res => res.json())
      .then(data => setEquipos(data.sports[0].leagues[0].teams))
      .catch(err => console.error("Error:", err));
  }, []);

  return (
    <div style={{ padding: '20px' }}>
      <h1 style={{ textAlign: 'center', color: '#1d428a' }}>NBA Proyect API</h1>
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', 
        gap: '20px' 
      }}>
        {equipos.map(t => (
          <div key={t.team.id} style={{ 
            border: '1px solid #ddd', 
            borderRadius: '10px', 
            padding: '15px', 
            textAlign: 'center',
            boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
          }}>
            <img src={t.team.logos[0].href} alt={t.team.name} style={{ width: '100px' }} />
            <h3>{t.team.displayName}</h3>
            <p>Abreviación: {t.team.abbreviation}</p>
            <button style={{
              backgroundColor: '#' + t.team.color,
              color: 'white',
              border: 'none',
              padding: '10px',
              borderRadius: '5px',
              cursor: 'pointer'
            }}>
              Ver Equipo
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Home;
